package com.courassistant.java.ui;

import android.Manifest;
import android.content.Intent;
import android.content.pm.PackageManager;
import android.os.Build;
import android.os.Bundle;
import android.view.MenuItem;
import androidx.annotation.NonNull;
import androidx.appcompat.app.AppCompatActivity;
import androidx.core.app.ActivityCompat;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.Fragment;
import com.google.android.material.bottomnavigation.BottomNavigationView;
import com.courassistant.R;
import java.util.ArrayList;
import java.util.List;

/**
 * 主界面 - 宋氏美学
 * 单夫纯律师 制作
 */
public class MainActivity extends AppCompatActivity {

    private static final int REQUEST_PERMISSIONS_CODE = 100;

    // 需要的权限列表
    private static final String[] REQUIRED_PERMISSIONS = {
        Manifest.permission.READ_SMS,
        Manifest.permission.RECEIVE_SMS,
        Manifest.permission.READ_EXTERNAL_STORAGE,
        Manifest.permission.WRITE_EXTERNAL_STORAGE
    };

    private BottomNavigationView bottomNavigation;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        // 初始化视图
        initViews();

        // 请求权限
        requestPermissions();

        // 设置底部导航
        setupBottomNavigation();

        // 默认显示短信列表
        loadFragment(new SmsFragment());
    }

    /**
     * 初始化视图
     */
    private void initViews() {
        bottomNavigation = findViewById(R.id.bottom_navigation);
    }

    /**
     * 设置底部导航
     */
    private void setupBottomNavigation() {
        bottomNavigation.setOnItemSelectedListener(new BottomNavigationView.OnItemSelectedListener() {
            @Override
            public boolean onNavigationItemSelected(@NonNull MenuItem item) {
                Fragment fragment = null;
                int itemId = item.getItemId();

                if (itemId == R.id.nav_sms) {
                    fragment = new SmsFragment();
                } else if (itemId == R.id.nav_docs) {
                    fragment = new DocsFragment();
                } else if (itemId == R.id.nav_settings) {
                    fragment = new SettingsFragment();
                }

                if (fragment != null) {
                    loadFragment(fragment);
                    return true;
                }

                return false;
            }
        });
    }

    /**
     * 加载Fragment
     */
    private void loadFragment(Fragment fragment) {
        getSupportFragmentManager()
            .beginTransaction()
            .replace(R.id.fragment_container, fragment)
            .commit();
    }

    /**
     * 请求权限
     */
    private void requestPermissions() {
        List<String> neededPermissions = new ArrayList<>();

        for (String permission : REQUIRED_PERMISSIONS) {
            if (ContextCompat.checkSelfPermission(this, permission)
                != PackageManager.PERMISSION_GRANTED) {
                neededPermissions.add(permission);
            }
        }

        if (!neededPermissions.isEmpty()) {
            ActivityCompat.requestPermissions(
                this,
                neededPermissions.toArray(new String[0]),
                REQUEST_PERMISSIONS_CODE
            );
        }
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                         @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);

        if (requestCode == REQUEST_PERMISSIONS_CODE) {
            // 权限请求结果处理
            for (int result : grantResults) {
                if (result != PackageManager.PERMISSION_GRANTED) {
                    // 权限被拒绝
                    showPermissionDeniedMessage();
                    return;
                }
            }
        }
    }

    /**
     * 显示权限被拒绝提示
     */
    private void showPermissionDeniedMessage() {
        // 这里可以显示一个Dialog或Toast提示用户
        // 为简化代码，这里省略实现
    }
}

package com.courassistant.java.ui;

import android.database.Cursor;
import android.net.Uri;
import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.HorizontalScrollView;
import android.widget.LinearLayout;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.courassistant.R;
import com.courassistant.java.model.SmsMessage;
import com.courassistant.java.adapter.SmsMenuAdapter;
import com.courassistant.java.adapter.PdfCardAdapter;
import java.util.ArrayList;
import java.util.List;
import java.util.regex.Matcher;
import java.util.regex.Pattern;

/**
 * 短信列表界面 - 宋氏美学
 * 单夫纯律师 制作
 */
public class SmsFragment extends Fragment {

    private RecyclerView menuRecyclerView;
    private RecyclerView pdfRecyclerView;
    private SmsMenuAdapter menuAdapter;
    private PdfCardAdapter pdfAdapter;
    private TextView emptyView;

    private List<SmsMenu> smsMenus = new ArrayList<>();
    private List<PdfDocument> pdfDocuments = new ArrayList<>();

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                           @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_sms, container, false);

        initViews(view);
        setupMenus();
        loadSmsMessages();

        return view;
    }

    /**
     * 初始化视图
     */
    private void initViews(View view) {
        menuRecyclerView = view.findViewById(R.id.menu_recycler_view);
        pdfRecyclerView = view.findViewById(R.id.pdf_recycler_view);
        emptyView = view.findViewById(R.id.empty_view);

        // 设置横向滚动菜单
        LinearLayoutManager menuLayoutManager = new LinearLayoutManager(
            getContext(),
            LinearLayoutManager.HORIZONTAL,
            false
        );
        menuRecyclerView.setLayoutManager(menuLayoutManager);

        menuAdapter = new SmsMenuAdapter(smsMenus, new SmsMenuAdapter.OnMenuClickListener() {
            @Override
            public void onMenuClick(SmsMenu menu) {
                showPdfDocuments(menu);
            }
        });
        menuRecyclerView.setAdapter(menuAdapter);

        // 设置PDF卡片列表
        LinearLayoutManager pdfLayoutManager = new LinearLayoutManager(getContext());
        pdfRecyclerView.setLayoutManager(pdfLayoutManager);

        pdfAdapter = new PdfCardAdapter(pdfDocuments);
        pdfRecyclerView.setAdapter(pdfAdapter);
    }

    /**
     * 设置菜单分类
     */
    private void setupMenus() {
        smsMenus.clear();
        smsMenus.add(new SmsMenu("全部", 0));
        smsMenus.add(new SmsMenu("开庭通知", 1));
        smsMenus.add(new SmsMenu("传票", 2));
        smsMenus.add(new SmsMenu("判决书", 3));
        smsMenus.add(new SmsMenu("调解书", 4));
        smsMenus.add(new SmsMenu("执行通知", 5));
        smsMenus.add(new SmsMenu("其他", 6));

        menuAdapter.notifyDataSetChanged();
    }

    /**
     * 加载短信消息
     */
    private void loadSmsMessages() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                List<SmsMessage> messages = readSmsFromInbox();

                getActivity().runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        if (messages.isEmpty()) {
                            emptyView.setVisibility(View.VISIBLE);
                            pdfRecyclerView.setVisibility(View.GONE);
                        } else {
                            emptyView.setVisibility(View.GONE);
                            pdfRecyclerView.setVisibility(View.VISIBLE);
                            processSmsMessages(messages);
                        }
                    }
                });
            }
        }).start();
    }

    /**
     * 从收件箱读取短信
     */
    private List<SmsMessage> readSmsFromInbox() {
        List<SmsMessage> messages = new ArrayList<>();
        Uri inboxUri = Uri.parse("content://sms/inbox");

        String[] projection = {
            "_id",
            "address",
            "body",
            "date",
            "read"
        };

        Cursor cursor = null;
        try {
            cursor = getContext().getContentResolver().query(
                inboxUri,
                projection,
                null,
                null,
                "date DESC"
            );

            if (cursor != null && cursor.moveToFirst()) {
                int idIndex = cursor.getColumnIndex("_id");
                int addressIndex = cursor.getColumnIndex("address");
                int bodyIndex = cursor.getColumnIndex("body");
                int dateIndex = cursor.getColumnIndex("date");
                int readIndex = cursor.getColumnIndex("read");

                do {
                    SmsMessage message = new SmsMessage();
                    message.setId(cursor.getLong(idIndex));
                    message.setAddress(cursor.getString(addressIndex));
                    message.setBody(cursor.getString(bodyIndex));
                    message.setDate(cursor.getLong(dateIndex));
                    message.setRead(cursor.getInt(readIndex) == 1);

                    // 过滤法院短信
                    if (isCourtSms(message)) {
                        messages.add(message);
                    }
                } while (cursor.moveToNext());
            }
        } catch (Exception e) {
            e.printStackTrace();
        } finally {
            if (cursor != null) {
                cursor.close();
            }
        }

        return messages;
    }

    /**
     * 判断是否为法院短信
     */
    private boolean isCourtSms(SmsMessage message) {
        String body = message.getBody();
        String[] courtKeywords = {
            "法院", "开庭", "传票", "判决", "调解", "执行",
            "举证", "庭询", "听证", "送达"
        };

        for (String keyword : courtKeywords) {
            if (body.contains(keyword)) {
                return true;
            }
        }

        return false;
    }

    /**
     * 处理短信消息
     */
    private void processSmsMessages(List<SmsMessage> messages) {
        pdfDocuments.clear();

        for (SmsMessage message : messages) {
            PdfDocument doc = new PdfDocument();
            doc.setTitle(extractTitle(message.getBody()));
            doc.setDate(formatDate(message.getDate()));
            doc.setCourtName(extractCourtName(message.getBody()));
            doc.setCaseNumber(extractCaseNumber(message.getBody()));
            doc.setSmsBody(message.getBody());

            pdfDocuments.add(doc);
        }

        pdfAdapter.notifyDataSetChanged();
    }

    /**
     * 提取标题
     */
    private String extractTitle(String body) {
        if (body.contains("开庭")) return "开庭通知";
        if (body.contains("传票")) return "传票";
        if (body.contains("判决")) return "判决书";
        if (body.contains("调解")) return "调解书";
        if (body.contains("执行")) return "执行通知";
        return "法院通知";
    }

    /**
     * 提取法院名称
     */
    private String extractCourtName(String body) {
        Pattern pattern = Pattern.compile("(.*?法院)");
        Matcher matcher = pattern.matcher(body);
        if (matcher.find()) {
            return matcher.group(1);
        }
        return "未知法院";
    }

    /**
     * 提取案号
     */
    private String extractCaseNumber(String body) {
        Pattern pattern = Pattern.compile("[(（]\\d{4}[^)）]*[)）]");
        Matcher matcher = pattern.matcher(body);
        if (matcher.find()) {
            return matcher.group(0);
        }
        return "";
    }

    /**
     * 格式化日期
     */
    private String formatDate(long timestamp) {
        java.text.SimpleDateFormat sdf = new java.text.SimpleDateFormat("yyyy年MM月dd日", java.util.Locale.CHINA);
        return sdf.format(new java.util.Date(timestamp));
    }

    /**
     * 显示指定菜单的PDF文档
     */
    private void showPdfDocuments(SmsMenu menu) {
        // 更新选中状态
        for (SmsMenu m : smsMenus) {
            m.setSelected(false);
        }
        menu.setSelected(true);
        menuAdapter.notifyDataSetChanged();

        // 这里可以根据菜单类型过滤PDF文档
        // 为简化代码，显示所有文档
    }

    /**
     * 短信菜单数据类
     */
    public static class SmsMenu {
        private String name;
        private int type;
        private boolean selected;

        public SmsMenu(String name, int type) {
            this.name = name;
            this.type = type;
            this.selected = false;
        }

        public String getName() { return name; }
        public int getType() { return type; }
        public boolean isSelected() { return selected; }
        public void setSelected(boolean selected) { this.selected = selected; }
    }

    /**
     * PDF文档数据类
     */
    public static class PdfDocument {
        private String title;
        private String date;
        private String courtName;
        private String caseNumber;
        private String smsBody;

        public String getTitle() { return title; }
        public void setTitle(String title) { this.title = title; }

        public String getDate() { return date; }
        public void setDate(String date) { this.date = date; }

        public String getCourtName() { return courtName; }
        public void setCourtName(String courtName) { this.courtName = courtName; }

        public String getCaseNumber() { return caseNumber; }
        public void setCaseNumber(String caseNumber) { this.caseNumber = caseNumber; }

        public String getSmsBody() { return smsBody; }
        public void setSmsBody(String smsBody) { this.smsBody = smsBody; }
    }
}

package com.courassistant.java.ui;

import android.os.Bundle;
import android.os.Environment;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.LinearLayoutManager;
import androidx.recyclerview.widget.RecyclerView;
import com.courassistant.R;
import com.courassistant.java.adapter.DocumentListAdapter;
import java.io.File;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;
import java.util.Locale;

/**
 * 文档管理界面 - 宋氏美学
 * 单夫纯律师 制作
 */
public class DocsFragment extends Fragment {

    private RecyclerView docsRecyclerView;
    private DocumentListAdapter docsAdapter;
    private TextView emptyView;
    private TextView syncStatusView;

    private List<DocumentItem> documentItems = new ArrayList<>();

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                           @Nullable Bundle savedInstanceState) {
        View view = inflater.inflate(R.layout.fragment_docs, container, false);

        initViews(view);
        loadDocuments();
        updateSyncStatus();

        return view;
    }

    /**
     * 初始化视图
     */
    private void initViews(View view) {
        docsRecyclerView = view.findViewById(R.id.docs_recycler_view);
        emptyView = view.findViewById(R.id.empty_view);
        syncStatusView = view.findViewById(R.id.sync_status);

        // 设置文档列表
        LinearLayoutManager layoutManager = new LinearLayoutManager(getContext());
        docsRecyclerView.setLayoutManager(layoutManager);

        docsAdapter = new DocumentListAdapter(documentItems);
        docsRecyclerView.setAdapter(docsAdapter);
    }

    /**
     * 加载文档
     */
    private void loadDocuments() {
        new Thread(new Runnable() {
            @Override
            public void run() {
                List<DocumentItem> items = scanDocuments();

                getActivity().runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        documentItems.clear();
                        documentItems.addAll(items);

                        if (documentItems.isEmpty()) {
                            emptyView.setVisibility(View.VISIBLE);
                            docsRecyclerView.setVisibility(View.GONE);
                        } else {
                            emptyView.setVisibility(View.GONE);
                            docsRecyclerView.setVisibility(View.VISIBLE);
                        }

                        docsAdapter.notifyDataSetChanged();
                    }
                });
            }
        }).start();
    }

    /**
     * 扫描文档目录
     */
    private List<DocumentItem> scanDocuments() {
        List<DocumentItem> items = new ArrayList<>();

        // 扫描应用专属目录
        File appDir = new File(
            Environment.getExternalStorageDirectory(),
            "CourtAssistant/Documents"
        );

        if (!appDir.exists()) {
            appDir.mkdirs();
        }

        File[] files = appDir.listFiles();
        if (files != null) {
            for (File file : files) {
                if (file.isDirectory()) {
                    // 处理分类目录
                    DocumentItem item = new DocumentItem();
                    item.setType(DocumentItem.TYPE_HEADER);
                    item.setTitle(file.getName());
                    item.setFileCount(countFiles(file));
                    items.add(item);

                    // 添加该目录下的文件
                    List<File> pdfFiles = getPdfFiles(file);
                    for (File pdfFile : pdfFiles) {
                        DocumentItem docItem = new DocumentItem();
                        docItem.setType(DocumentItem.TYPE_DOCUMENT);
                        docItem.setTitle(pdfFile.getName());
                        docItem.setPath(pdfFile.getAbsolutePath());
                        docItem.setDate(formatFileDate(pdfFile.lastModified()));
                        docItem.setSize(formatFileSize(pdfFile.length()));
                        items.add(docItem);
                    }
                } else if (file.getName().toLowerCase().endsWith(".pdf")) {
                    // 处理根目录下的PDF文件
                    DocumentItem item = new DocumentItem();
                    item.setType(DocumentItem.TYPE_DOCUMENT);
                    item.setTitle(file.getName());
                    item.setPath(file.getAbsolutePath());
                    item.setDate(formatFileDate(file.lastModified()));
                    item.setSize(formatFileSize(file.length()));
                    items.add(item);
                }
            }
        }

        return items;
    }

    /**
     * 获取PDF文件列表
     */
    private List<File> getPdfFiles(File directory) {
        List<File> pdfFiles = new ArrayList<>();
        File[] files = directory.listFiles();

        if (files != null) {
            for (File file : files) {
                if (file.isFile() && file.getName().toLowerCase().endsWith(".pdf")) {
                    pdfFiles.add(file);
                }
            }
        }

        return pdfFiles;
    }

    /**
     * 统计文件数量
     */
    private int countFiles(File directory) {
        int count = 0;
        File[] files = directory.listFiles();

        if (files != null) {
            for (File file : files) {
                if (file.isFile() && file.getName().toLowerCase().endsWith(".pdf")) {
                    count++;
                }
            }
        }

        return count;
    }

    /**
     * 格式化文件日期
     */
    private String formatFileDate(long timestamp) {
        SimpleDateFormat sdf = new SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.CHINA);
        return sdf.format(new Date(timestamp));
    }

    /**
     * 格式化文件大小
     */
    private String formatFileSize(long size) {
        if (size < 1024) {
            return size + " B";
        } else if (size < 1024 * 1024) {
            return String.format(Locale.CHINA, "%.1f KB", size / 1024.0);
        } else {
            return String.format(Locale.CHINA, "%.1f MB", size / (1024.0 * 1024));
        }
    }

    /**
     * 更新同步状态
     */
    private void updateSyncStatus() {
        // 模拟日历同步状态
        String lastSync = "上次同步: " + new SimpleDateFormat("yyyy-MM-dd HH:mm", Locale.CHINA)
            .format(new Date());

        syncStatusView.setText(lastSync);
    }

    /**
     * 文档项数据类
     */
    public static class DocumentItem {
        public static final int TYPE_HEADER = 1;
        public static final int TYPE_DOCUMENT = 2;

        private int type;
        private String title;
        private String path;
        private String date;
        private String size;
        private int fileCount;
        private boolean expanded;

        public int getType() { return type; }
        public void setType(int type) { this.type = type; }

        public String getTitle() { return title; }
        public void setTitle(String title) { this.title = title; }

        public String getPath() { return path; }
        public void setPath(String path) { this.path = path; }

        public String getDate() { return date; }
        public void setDate(String date) { this.date = date; }

        public String getSize() { return size; }
        public void setSize(String size) { this.size = size; }

        public int getFileCount() { return fileCount; }
        public void setFileCount(int count) { fileCount = count; }

        public boolean isExpanded() { return expanded; }
        public void setExpanded(boolean expanded) { this.expanded = expanded; }
    }
}

