package com.courassistant.java.adapter;

import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.recyclerview.widget.RecyclerView;
import com.courassistant.R;
import com.courassistant.java.ui.SmsFragment;
import java.util.List;

/**
 * 短信菜单适配器 - 宋氏美学
 * 单夫纯律师 制作
 */
public class SmsMenuAdapter extends RecyclerView.Adapter<SmsMenuAdapter.MenuViewHolder> {

    private List<SmsFragment.SmsMenu> menus;
    private OnMenuClickListener listener;

    public interface OnMenuClickListener {
        void onMenuClick(SmsFragment.SmsMenu menu);
    }

    public SmsMenuAdapter(List<SmsFragment.SmsMenu> menus, OnMenuClickListener listener) {
        this.menus = menus;
        this.listener = listener;
    }

    @NonNull
    @Override
    public MenuViewHolder onCreateViewHolder(@NonNull ViewGroup parent, int viewType) {
        View view = LayoutInflater.from(parent.getContext())
            .inflate(R.layout.item_sms_menu, parent, false);
        return new MenuViewHolder(view);
    }

    @Override
    public void onBindViewHolder(@NonNull MenuViewHolder holder, int position) {
        SmsFragment.SmsMenu menu = menus.get(position);
        holder.bind(menu, listener);
    }

    @Override
    public int getItemCount() {
        return menus.size();
    }

    static class MenuViewHolder extends RecyclerView.ViewHolder {
        private TextView menuName;
        private View cardView;

        public MenuViewHolder(@NonNull View itemView) {
            super(itemView);
            menuName = itemView.findViewById(R.id.menu_name);
            cardView = itemView.findViewById(R.id.menu_card);
        }

        public void bind(SmsFragment.SmsMenu menu, OnMenuClickListener listener) {
            menuName.setText(menu.getName());

            // 设置选中状态
            if (menu.isSelected()) {
                cardView.setSelected(true);
                cardView.setAlpha(1.0f);
            } else {
                cardView.setSelected(false);
