        DocsFragment.DocumentItem item = items.get(position);

        if (holder instanceof HeaderViewHolder) {
            ((HeaderViewHolder) holder).bind(item);
        } else if (holder instanceof DocumentViewHolder) {
            ((DocumentViewHolder) holder).bind(item);
        }
