private boolean isCourtSms(SmsMessage message) {
    String body = message.getBody();
    String[] courtKeywords = {
        "法院", "开庭", "传票", "判决", "调解", "执行",
        "举证", "庭询", "听证", "送达"
    };

    for (String keyword : courtKeywords) {
        if (body.contains(keyword)) {
            return true;
        }
    }
    return false;
}
