private String extractCourtName(String body) {
    Pattern pattern = Pattern.compile("(.*?法院)");
    Matcher matcher = pattern.matcher(body);
    if (matcher.find()) {
        return matcher.group(1);
    }
    return "未知法院";
}

// 提取案号
private String extractCaseNumber(String body) {
    Pattern pattern = Pattern.compile("[(（]\\d{4}[^)）]*[)）]");
    Matcher matcher = pattern.matcher(body);
    if (matcher.find()) {
        return matcher.group(0);
    }
    return "";
}
