## 文档扫描 (DocsFragment.java)

```java
private List<DocumentItem> scanDocuments() {
    List<DocumentItem> items = new ArrayList<>();

    File appDir = new File(
        Environment.getExternalStorageDirectory(),
        "CourtAssistant/Documents"
    );

    File[] files = appDir.listFiles();
    if (files != null) {
        for (File file : files) {
            if (file.isDirectory()) {
                // 处理分类目录
                DocumentItem item = new DocumentItem();
                item.setType(DocumentItem.TYPE_HEADER);
                item.setTitle(file.getName());
                item.setFileCount(countFiles(file));
                items.add(item);

                // 添加该目录下的文件
                List<File> pdfFiles = getPdfFiles(file);
                for (File pdfFile : pdfFiles) {
                    DocumentItem docItem = new DocumentItem();
                    docItem.setType(DocumentItem.TYPE_DOCUMENT);
                    docItem.setTitle(pdfFile.getName());
                    docItem.setPath(pdfFile.getAbsolutePath());
                    docItem.setDate(formatFileDate(pdfFile.lastModified()));
                    docItem.setSize(formatFileSize(pdfFile.length()));
                    items.add(docItem);
                }
            }
        }
    }

    return items;
}
